---
/**
 * ButtonGroup.astro -- astro-shad button group. Converted from the shadcn
 * base-ui button-group (cva + useRender), minus react. Zero client JS:
 * the whole mechanic is child combinator CSS -- children lose their inner
 * radii and collapse shared borders; only the group's outer corners stay
 * rounded. Works on any children (Button, <a>, ButtonGroupText,
 * ButtonGroupSeparator), so the source's data-slot bookkeeping is
 * replaced with plain *:first/last-child selectors. The source's
 * select-trigger/input special cases are dropped (no such primitives
 * here); radius overrides carry `!` because they must beat the radius a
 * child brings along (same specificity tier otherwise).
 *
 * Nesting groups inside a group spaces them with gap-2 (split-button
 * pattern), keyed off data-slot="button-group" which this file still
 * emits for shadcn compatibility.
 *
 *   <ButtonGroup>
 *     <Button variant="outline">Copy</Button>
 *     <Button variant="outline">Paste</Button>
 *   </ButtonGroup>
 *   <ButtonGroup orientation="vertical">...</ButtonGroup>
 */
import { cn } from '../../lib/utils';

type Orientation = 'horizontal' | 'vertical';

const BASE =
  'flex w-fit items-stretch *:focus-visible:relative *:focus-visible:z-10 has-[>[data-slot=button-group]]:gap-2';

const ORIENTATIONS: Record<Orientation, string> = {
  horizontal:
    '[&>*]:rounded-none! [&>*:first-child]:rounded-l-md! [&>*:last-child]:rounded-r-md! [&>*:not(:first-child)]:border-l-0',
  vertical:
    'flex-col [&>*]:rounded-none! [&>*:first-child]:rounded-t-md! [&>*:last-child]:rounded-b-md! [&>*:not(:first-child)]:border-t-0',
};

interface Props {
  orientation?: Orientation;
  class?: string;
  [key: string]: unknown;
}

const { orientation = 'horizontal', class: className, ...rest } = Astro.props;
---

<div
  role="group"
  data-slot="button-group"
  data-orientation={orientation}
  class={cn(BASE, ORIENTATIONS[orientation], className)}
  {...rest}
>
  <slot />
</div>

---
/**
 * ButtonGroupText.astro -- static text cell for ButtonGroup (a prefix
 * label, a unit, an icon). Converted from the shadcn base-ui
 * ButtonGroupText; the useRender polymorphism becomes an `as` prop
 * (pass as="label" + for to caption an input in the group).
 *
 *   <ButtonGroup>
 *     <ButtonGroupText>https://</ButtonGroupText>
 *     <Button variant="outline">example.com</Button>
 *   </ButtonGroup>
 */
import { cn } from '../../lib/utils';

interface Props {
  /** wrapper tag */
  as?: string;
  class?: string;
  [key: string]: unknown;
}

const { as = 'div', class: className, ...rest } = Astro.props;
const Tag = as as any;
---

<Tag
  data-slot="button-group-text"
  class={cn(
    "flex items-center gap-2 rounded-md border border-border bg-muted px-2.5 text-sm font-medium [&_svg]:pointer-events-none [&_svg:not([class*='size-'])]:size-4",
    className
  )}
  {...rest}
>
  <slot />
</Tag>

---
/**
 * ButtonGroupSeparator.astro -- 1px divider between ButtonGroup children.
 * The shadcn base-ui version wraps their Separator primitive; there is no
 * separator in this registry (yet), so this inlines the same thing: a
 * bg-input line that self-stretches to the group's height. Orientation is
 * the LINE's own axis -- `vertical` (default) divides a horizontal group,
 * `horizontal` divides a vertical one.
 *
 *   <ButtonGroup>
 *     <Button variant="ghost">Undo</Button>
 *     <ButtonGroupSeparator />
 *     <Button variant="ghost">Redo</Button>
 *   </ButtonGroup>
 */
import { cn } from '../../lib/utils';

type Orientation = 'horizontal' | 'vertical';

const ORIENTATIONS: Record<Orientation, string> = {
  vertical: 'mx-px w-px',
  horizontal: 'my-px h-px w-auto',
};

interface Props {
  orientation?: Orientation;
  class?: string;
  [key: string]: unknown;
}

const { orientation = 'vertical', class: className, ...rest } = Astro.props;
---

<div
  role="separator"
  aria-orientation={orientation}
  data-slot="button-group-separator"
  class={cn('relative self-stretch bg-input', ORIENTATIONS[orientation], className)}
  {...rest}
>
</div>
